import java.io.*;
import javax.servlet.*;
import javax.servlet.http.*;

public class SecureServlet extends HttpServlet {
    protected void doPost(HttpServletRequest request, HttpServletResponse response)
            throws ServletException, IOException {
        String userInput = request.getParameter("input");
        PrintWriter out = response.getWriter();
        out.println("<html>");
        out.println("<body>");
        out.println("<p>User input: " + sanitizeInput(userInput) + "</p>"); // Sanitize user input before embedding it into the HTML response
        out.println("</body>");
        out.println("</html>");
    }

    private String sanitizeInput(String input) {
        // Implement proper sanitization logic here to prevent XSS attacks
        // One common approach is to escape special characters
        return input == null ? "" : input.replaceAll("<", "&lt;").replaceAll(">", "&gt;");
    }
}

### Explanation:
취약유형: Cross-Site Scripting (XSS)
